import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Card, Badge, icon } from 'decantr/components';

code.example:
function ProductCardGrid({ product, onClick }) {
  const { div, img, h3, span } = tags;
  const typeIcon = { image: 'image', video: 'video', audio: 'music', document: 'file-text' };

  return Card({ class: css('studio-card _overflow[hidden] _trans _hover:shadow _cursor[pointer]'), onclick: () => onClick?.(product) },
    div({ class: css('_relative _aspect[16/9] _bgmuted/10') },
      product.thumbnail
        ? img({ src: product.thumbnail, class: css('_wfull _hfull _objcover') })
        : div({ class: css('_flex _center _hfull') },
            icon(typeIcon[product.type] || 'file', { size: '32', class: css('_fgmuted') })
          ),
      product.locked ? div({ class: css('_absolute _inset0 studio-gate-blur _flex _center') },
        div({ class: css('_w10 _h10 _r[50%] _bgbg _flex _center _shadow') },
          icon('lock', { size: '20', class: css('_fgmuted') })
        )
      ) : null,
      product.type === 'video' ? div({ class: css('_absolute _bottom2 _right2 _px2 _py1 _r1 _bg[rgba(0,0,0,0.7)] _text[white] _textxs') },
        product.duration || '0:00'
      ) : null,
      div({ class: css('_absolute _top2 _left2') },
        Badge({ variant: 'secondary', size: 'xs', class: css('_bgbg/80') },
          icon(typeIcon[product.type], { size: '12', class: css('_mr1') }),
          product.type
        )
      )
    ),
    div({ class: css('_p4') },
      h3({ class: css('_fontmedium _truncate _mb2') }, product.title),
      div({ class: css('_flex _jcsb _aic') },
        product.price > 0
          ? span({ class: css('_fontmedium _fgPrimary') }, '$', product.price)
          : Badge({ variant: 'secondary', size: 'sm' }, product.tierName || 'Free'),
        div({ class: css('_flex _aic _gap2 _textsm _fgmuted') },
          div({ class: css('_flex _aic _gap1') }, icon('heart', { size: '14' }), product.likes || 0),
          div({ class: css('_flex _aic _gap1') }, icon('message-circle', { size: '14' }), product.comments || 0)
        )
      )
    )
  );
}

