function FeaturedProductCard({ product, onBuy }) {
  const { div, img, h2, p, span } = tags;

  return Card({ class: css('studio-card _overflow[hidden] _lg:flex') },
    div({ class: css('_lg:w[50%] _aspect[16/9] _lg:aspect[auto] _bgmuted/10') },
      product.thumbnail ? img({ src: product.thumbnail, class: css('_wfull _hfull _objcover') }) : null
    ),
    div({ class: css('_p6 _lg:w[50%] _flex _col _jcsb') },
      div({},
        div({ class: css('_flex _gap2 _mb3') },
          Badge({ variant: 'default' }, product.type),
          product.locked ? Badge({ variant: 'secondary' }, 'Premium') : null
        ),
        h2({ class: css('_heading3 _mb3') }, product.title),
        p({ class: css('_fgmuted _mb4') }, product.description)
      ),
      div({ class: css('_flex _aic _jcsb') },
        div({ class: css('_flex _aic _gap4') },
          span({ class: css('_heading3 _fgPrimary') }, '$', product.price),
          div({ class: css('_flex _aic _gap3 _fgmuted _textsm') },
            div({ class: css('_flex _aic _gap1') }, icon('heart', { size: '16' }), product.likes),
            div({ class: css('_flex _aic _gap1') }, icon('eye', { size: '16' }), product.views)
          )
        ),
        div({ class: css('_flex _gap2') },
          Button({ variant: 'ghost' }, icon('share-2')),
          Button({ variant: 'primary', onclick: () => onBuy?.(product) }, 'Buy Now')
        )
      )
    )
